  domain(q6, [0,1,2,3,4,5,6,7]);
  domain(q7, [0,1,2,3,4,5,6,7]);
  plus(q0, 0, u0); minus(q0, 0, v0);
  plus(q1, 1, u1); minus(q1, 1, v1);
  plus(q2, 2, u2); minus(q2, 2, v2);
  plus(q3, 3, u3); minus(q3, 3, v3);
  plus(q4, 4, u4); minus(q4, 4, v4);
