  all_different([v08,v18,v28,v38,v48,v58,v68,v78,v88]);
  all_different([v00,v01,v02,v10,v11,v12,v20,v21,v22]);
  all_different([v03,v04,v05,v13,v14,v15,v23,v24,v25]);
  all_different([v06,v07,v08,v16,v17,v18,v26,v27,v28]);
